import { useState, useEffect, useCallback, useRef, useMemo } from 'react';

/**
 * Custom hook for managing RefCodeManager state
 * Extracts all state management logic to make the component more modular
 */
export const useRefCodeManagerState = ({ refCodeId, initialData: propsInitialData, onSuccess, onCancel }) => {
  // Core state - Always show drawer for this component
  const [drawerOpen, setDrawerOpen] = useState(true);
  const [toast, setToast] = useState({ open: false, message: '', type: 'info', duration: 3000 });
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  
  // Form and data state
  const formRef = useRef(null);
  const [initialData, setInitialData] = useState(null);
  
  // Confirmation dialog state
  const [confirmationDialog, setConfirmationDialog] = useState({
    open: false,
    title: '',
    message: '',
    onConfirm: null,
    onCancel: null,
    confirmText: 'Yes',
    cancelText: 'No',
    severity: 'warning'
  });

  // Auto-open drawer when component mounts (always show drawer for this component)
  useEffect(() => {
    // Always show drawer when component is mounted
    setDrawerOpen(true);
  }, []); // Empty dependency array - only run once on mount

  // Load data function
  const loadData = useCallback(async () => {
    if (!refCodeId || refCodeId === 0) {
      // New refcode - set default values
      setInitialData({
        Code: '',
        Description: '',
        Domain: '',
        Meaning: '',
        Active: false,
        Order: 0,
        Id: 0,
        LockId: 0,
        AgencyId: 0
      });
      setLoading(false);
      return;
    }

    try {
      setLoading(true);
      setError(null);
      
      // Use provided initialData if available, otherwise set default values
      if (propsInitialData) {
        setInitialData(propsInitialData);
      } else {
        // Fallback to default values if no initialData provided
        setInitialData({
          Code: '',
          Description: '',
          Domain: '',
          Meaning: '',
          Active: false,
          Order: 0,
          Id: refCodeId,
          LockId: 0,
          AgencyId: 0
        });
      }
      
    } catch (err) {
      console.error('Error loading refcode data:', err);
      setError(err.message || 'Failed to load refcode data');
      setToast({
        open: true,
        message: 'Failed to load refcode data',
        type: 'error',
        duration: 5000
      });
    } finally {
      setLoading(false);
    }
  }, [refCodeId]); // Remove propsInitialData from dependencies

  // Load data on mount and when refCodeId changes
  useEffect(() => {
    loadData();
  }, [refCodeId]); // Only depend on refCodeId, not loadData

  // Memoize propsInitialData to prevent infinite loops
  const memoizedInitialData = useMemo(() => propsInitialData, [
    propsInitialData?.Id,
    propsInitialData?.Code,
    propsInitialData?.Description,
    propsInitialData?.Domain,
    propsInitialData?.Meaning,
    propsInitialData?.Active,
    propsInitialData?.Order,
    propsInitialData?.LockId,
    propsInitialData?.AgencyId
  ]);

  // Handle initialData changes separately
  useEffect(() => {
    if (memoizedInitialData && refCodeId && refCodeId !== 0) {
      setInitialData(memoizedInitialData);
    }
  }, [memoizedInitialData, refCodeId]);

  return {
    // Core state
    drawerOpen,
    setDrawerOpen,
    toast,
    setToast,
    saving,
    setSaving,
    loading,
    setLoading,
    error,
    setError,
    
    // Form state
    formRef,
    initialData,
    setInitialData,
    
    // Dialog state
    confirmationDialog,
    setConfirmationDialog,
    
    // Actions
    loadData
  };
};
