import { colors } from '../../../../utils/designTokens';

/**
 * Shared form field styles for consistent styling across forms
 * Includes z-index fixes to prevent border disappearing issues with autocomplete
 */

/**
 * Common input field styles with border persistence
 * Use for FAWInput components
 */
export const getInputFieldStyles = (backgroundColor = colors.background.default) => ({
  zIndex: '0 !important',
  position: 'relative',
  '& .MuiOutlinedInput-root': {
    backgroundColor: `${backgroundColor} !important`,
    zIndex: '0 !important',
    position: 'relative',
    '& input': {
      zIndex: '0 !important',
    },
    '& fieldset': {
      borderColor: 'rgba(0, 0, 0, 0.23) !important',
      zIndex: '0 !important',
    },
    '&:hover fieldset': {
      borderColor: 'rgba(0, 0, 0, 0.87) !important',
    },
    '&.Mui-focused fieldset': {
      borderColor: `${colors.primary?.main || '#1976d2'} !important`,
      borderWidth: '2px !important',
    },
    '&.Mui-disabled fieldset': {
      borderColor: 'rgba(0, 0, 0, 0.12) !important',
    },
  },
  '& input': {
    zIndex: '0 !important',
  }
});

