/**
 * Generic form field styles factory
 * @param {string} fieldType - Type of field: 'input', 'textarea', 'select'
 * @param {string} backgroundColor - Background color (default: colors.background.default)
 * @returns {Object} Style object for the specified field type
 */
export const getFormFieldStyles = (fieldType = 'input', backgroundColor = colors.background.default) => {
  switch (fieldType) {
    case 'textarea':
      return getTextareaFieldStyles(backgroundColor);
    case 'select':
      return getSelectFieldStyles(backgroundColor);
    case 'input':
    default:
      return getInputFieldStyles(backgroundColor);
  }
};

// Preset styles for common use cases
export const formFieldStyles = {
  input: getInputFieldStyles(),
  textarea: getTextareaFieldStyles(),
  select: getSelectFieldStyles(),
  inputWhite: getInputFieldStyles('#ffffff'),
  textareaWhite: getTextareaFieldStyles('#ffffff'),
  selectWhite: getSelectFieldStyles('#ffffff'),
};
