import React, { forwardRef, useImperativeHandle, useState, useEffect } from 'react';
import { Box, Alert } from '@mui/material';
import FAWTypography from '../../FAWTypography';
import FAWSkeleton from '../../FAWSkeleton';
import FAWInput from '../../FAWInput';
import FAWTextarea from '../../FAWTextarea';
import FAWSelect from '../../FAWSelect';
import FAWCheckbox from '../../FAWCheckbox';
import FAWErrorBoundary from '../../errorHandling/FAWErrorBoundary';
import { colors } from '../../../../utils/designTokens';
import { formFieldStyles } from '../../shared/styles/formFieldStyles';
import '../styles/refcode.css';

const RefCodeForm = forwardRef(({
    refCodeId,
    onSave,
    onCancel,
    initialData,
    saving = false,
    refDomains = []
}, ref) => {
    const [formData, setFormData] = useState({
        Code: '',
        Description: '',
        Domain: '',
        Meaning: '',
        Active: false,
        Order: 0,
        Id: 0,
        LockId: 0,
        AgencyId: 0
    });
    const [errors, setErrors] = useState({});
    const [touched, setTouched] = useState({});
    const [loading, setLoading] = useState(false);

    // Initialize form data
    useEffect(() => {
        if (initialData) {
            const newFormData = {
                Code: initialData.Code || '',
                Description: initialData.Description || '',
                Domain: initialData.Domain || '',
                Meaning: initialData.Meaning || '',
                Active: initialData.Active !== undefined ? initialData.Active : false,
                Order: initialData.Order || 0,
                Id: initialData.Id || 0,
                LockId: initialData.LockId || 0,
                AgencyId: initialData.AgencyId || 0
            };
            setFormData(newFormData);
        }
    }, [initialData]);

    // Expose methods to parent component
    useImperativeHandle(ref, () => ({
        getFormData: () => formData,
        validateForm: validateForm,
        resetForm: resetForm
    }));

    const validateForm = () => {
        const newErrors = {};

        if (!formData.Code || formData.Code.trim() === '') {
            newErrors.Code = 'Code is required';
        } else if (formData.Code.length > 30) {
            newErrors.Code = 'Code cannot be more than 30 characters';
        }

        if (!formData.Description || formData.Description.trim() === '') {
            newErrors.Description = 'Description is required';
        } else if (formData.Description.length > 1000) {
            newErrors.Description = 'Description cannot be more than 1000 characters';
        }

        if (!formData.Domain || formData.Domain.trim() === '') {
            newErrors.Domain = 'Domain is required';
        }

        if (!formData.Meaning || formData.Meaning.trim() === '') {
            newErrors.Meaning = 'Meaning is required';
        } else if (formData.Meaning.length > 200) {
            newErrors.Meaning = 'Meaning cannot be more than 200 characters';
        }

        if (formData.Order !== null && formData.Order !== undefined && formData.Order < 0) {
            newErrors.Order = 'Order must be a positive number';
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const resetForm = () => {
        setFormData({
            Code: '',
            Description: '',
            Domain: '',
            Meaning: '',
            Active: false,
            Order: 0,
            Id: 0,
            LockId: 0,
            AgencyId: 0
        });
        setErrors({});
        setTouched({});
    };

    const handleFieldChange = (fieldName, value) => {
        setFormData(prev => ({
            ...prev,
            [fieldName]: value
        }));

        // Clear error when user starts typing
        if (errors[fieldName]) {
            setErrors(prev => ({
                ...prev,
                [fieldName]: ''
            }));
        }
    };

    const handleFieldBlur = (fieldName) => {
        setTouched(prev => ({
            ...prev,
            [fieldName]: true
        }));
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        if (validateForm()) {
            onSave(formData);
        }
    };

    if (loading || saving) {
        return (
            <Box sx={{ p: 3 }}>
                <FAWSkeleton variant="form" />
                {saving && (
                    <Box sx={{
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        mt: 2,
                        gap: 1
                    }}>
                        <FAWSkeleton variant="circular" width={20} height={20} />
                        <FAWTypography variant="body2" color="primary" sx={{ fontWeight: 'bold' }}>
                            Saving reference code...
                        </FAWTypography>
                    </Box>
                )}
            </Box>
        );
    }

    return (
        <FAWErrorBoundary
            title="Form Error"
            message="An error occurred while rendering the reference code form. Please try again."
            showDetails={false}
            onError={(error, errorInfo) => {
                console.error('RefCodeForm Error:', error, errorInfo);
            }}
        >
            <Box className="refcode-form-container" sx={{ p: 3 }}>
                <form className="refcode-form" onSubmit={(e) => e.preventDefault()}>
                    <Box className="refcode-form-fields" sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
                        {/* Code Input */}
                        <FAWInput
                            className="refcode-form-code-input"
                            id="refcode-code"
                            label="Code"
                            placeholder="Enter reference code"
                            value={formData.Code}
                            onChange={(e) => handleFieldChange('Code', e.target.value)}
                            onBlur={() => handleFieldBlur('Code')}
                            error={!!errors.Code}
                            helperText={errors.Code}
                            variant="outlined"
                            fullWidth
                            required
                            disabled={refCodeId && refCodeId !== 0} // Disable for existing codes
                            inputProps={{ maxLength: 30 }}
                            sx={formFieldStyles.input}
                        />

                        {/* Description Textarea */}
                        <FAWTextarea
                            className="refcode-form-description-textarea"
                            id="refcode-description"
                            label="Description"
                            placeholder="Enter reference code description"
                            value={formData.Description}
                            onChange={(e) => handleFieldChange('Description', e.target.value)}
                            onBlur={() => handleFieldBlur('Description')}
                            error={!!errors.Description}
                            helperText={errors.Description}
                            rows={3}
                            variant="outlined"
                            fullWidth
                            required
                            inputProps={{ maxLength: 1000 }}
                            sx={formFieldStyles.textarea}
                        />

                        {/* Domain Select */}
                        <FAWSelect
                            className="refcode-form-domain-select"
                            id="refcode-domain"
                            label="Domain"
                            value={formData.Domain}
                            onChange={(selectedOption, e) => {
                                handleFieldChange('Domain', selectedOption?.value || '');
                            }}
                            onBlur={() => handleFieldBlur('Domain')}
                            error={!!errors.Domain}
                            helperText={errors.Domain}
                            variant="outlined"
                            fullWidth
                            required
                            disabled={refCodeId && refCodeId !== 0} // Disable for existing codes
                            options={refDomains.map(domain => ({
                                value: domain.Name || '',
                                label: domain.Description && domain.Description !== domain.Name
                                    ? `${domain.Name} - ${domain.Description}`
                                    : domain.Name || ''
                            })).filter(option => option.value && option.value.trim() !== '')}
                            sx={formFieldStyles.select}
                            menuPortalTarget={document.body}
                            menuPosition="fixed"
                        />

                        {/* Meaning Input */}
                        <FAWInput
                            className="refcode-form-meaning-input"
                            id="refcode-meaning"
                            label="Meaning"
                            placeholder="Enter meaning"
                            value={formData.Meaning}
                            onChange={(e) => handleFieldChange('Meaning', e.target.value)}
                            onBlur={() => handleFieldBlur('Meaning')}
                            error={!!errors.Meaning}
                            helperText={errors.Meaning}
                            variant="outlined"
                            fullWidth
                            required
                            inputProps={{ maxLength: 200 }}
                            sx={formFieldStyles.input}
                        />

                        {/* Active Checkbox */}
                        <FAWCheckbox
                            className="refcode-form-active-checkbox"
                            id="refcode-active"
                            label="Active"
                            checked={formData.Active}
                            onChange={(e) => handleFieldChange('Active', e.target.checked)}
                            color="primary"
                        />

                        {/* Order Input */}
                        <FAWInput
                            className="refcode-form-order-input"
                            id="refcode-order"
                            label="Order"
                            placeholder="Enter order"
                            type="number"
                            value={formData.Order}
                            onChange={(e) => handleFieldChange('Order', parseInt(e.target.value) || 0)}
                            onBlur={() => handleFieldBlur('Order')}
                            error={!!errors.Order}
                            helperText={errors.Order}
                            variant="outlined"
                            fullWidth
                            inputProps={{ min: 0 }}
                            sx={formFieldStyles.input}
                        />

                        {/* Hidden Fields */}
                        <input type="hidden" name="Id" value={formData.Id} />
                        <input type="hidden" name="LockId" value={formData.LockId} />
                        <input type="hidden" name="AgencyId" value={formData.AgencyId} />
                    </Box>
                </form>
            </Box>
        </FAWErrorBoundary>
    );
});

RefCodeForm.displayName = 'RefCodeForm';

export default RefCodeForm;
