import { useCallback } from 'react';

/**
 * Custom hook for managing RefCodeManager handlers
 * Extracts all handler logic to make the component more modular
 */
export const useRefCodeManagerHandlers = ({
  refCodeId,
  onSuccess,
  onCancel,
  formRef,
  setSaving,
  setToast,
  setDrawerOpen,
  setError,
  setConfirmationDialog
}) => {

  const handleSaveClick = useCallback(async () => {
    if (!formRef.current) {
      console.error('Form ref not available');
      return;
    }

    try {
      setSaving(true);
      setError(null);

      // Get form data first
      const data = formRef.current.getFormData();
      if (!data) {
        console.error('Form data not available');
        setToast({
          open: true,
          message: 'Form data not available',
          type: 'error',
          duration: 3000
        });
        return;
      }

      // Validate form
      const isValid = formRef.current.validateForm();
      if (!isValid) {
        // Validation failed - return without showing toast message
        setSaving(false);
        return;
      }
      
      // Ensure all required fields are included
      const formData = {
        Code: data.Code,
        Description: data.Description,
        Domain: data.Domain,
        Meaning: data.Meaning,
        Active: data.Active,
        Order: data.Order,
        Id: data.Id,
        LockId: data.LockId,
        AgencyId: data.AgencyId
      };
      
      // Create form for submission
      const form = document.createElement('form');
      form.method = 'POST';
      form.action = '/RefCode/SaveRefCode';
      
      // Add anti-forgery token
      const token = document.querySelector('input[name="__RequestVerificationToken"]');
      if (token) {
        const tokenClone = token.cloneNode(true);
        form.appendChild(tokenClone);
      }

      // Add form data
      Object.keys(formData).forEach(key => {
        const input = document.createElement('input');
        input.type = 'hidden';
        input.name = `CurrentRefCode.${key}`;
        input.value = formData[key] !== null && formData[key] !== undefined ? formData[key] : '';
        form.appendChild(input);
      });

      // Submit form
      document.body.appendChild(form);
      form.submit();

    } catch (err) {
      console.error('Error saving refcode:', err);
      setError(err.message || 'Failed to save refcode');
      setToast({
        open: true,
        message: 'Failed to save refcode',
        type: 'error',
        duration: 5000
      });
    } finally {
      setSaving(false);
    }
  }, [formRef, setSaving, setToast, setError]);

  const handleCancel = useCallback(() => {
    setConfirmationDialog({
      open: true,
      title: 'Discard Changes',
      message: 'You haven\'t saved this domain yet. If you proceed, all information related to the domain you are currently creating will be lost.',
      confirmText: 'Continue',
      cancelText: 'Cancel',
      severity: 'warning',
      onConfirm: () => {
        setConfirmationDialog(prev => ({ ...prev, open: false }));
        if (onCancel) {
          onCancel();
        } else {
          // Default behavior - redirect to index
          window.location.href = '/RefCode';
        }
      },
      onCancel: () => {
        setConfirmationDialog(prev => ({ ...prev, open: false }));
      }
    });
  }, [onCancel, setConfirmationDialog]);

  const handleCloseDrawer = useCallback(() => {
    setDrawerOpen(false);
    if (onCancel) {
      onCancel();
    } else {
      // Default behavior - redirect to index
      window.location.href = '/RefCode';
    }
  }, [setDrawerOpen, onCancel]);

  const handleToastClose = useCallback(() => {
    setToast(prev => ({ ...prev, open: false }));
  }, [setToast]);

  return {
    handleSaveClick,
    handleCancel,
    handleCloseDrawer,
    handleToastClose
  };
};
